/* Minimal markdown renderer — covers LLM output patterns */
(function(g){
function md(src){
  if(!src)return '';
  var o='',lines=src.split('\n'),i=0,L=lines.length;
  function esc(s){return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
  function inline(s){
    // fenced code already stripped; handle inline
    return s
      .replace(/`([^`]+)`/g,function(_,c){return '<code>'+esc(c)+'</code>';})
      .replace(/\*\*([^*]+)\*\*/g,'<strong>$1</strong>')
      .replace(/__([^_]+)__/g,'<strong>$1</strong>')
      .replace(/\*([^*]+)\*/g,'<em>$1</em>')
      .replace(/_([^_]+)_/g,'<em>$1</em>')
      .replace(/\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g,'<a href="$2" target="_blank" rel="noopener">$1</a>');
  }
  while(i<L){
    var line=lines[i];
    // fenced code block
    if(/^```/.test(line)){
      var lang=(line.slice(3).trim()||'');
      var code='';
      i++;
      while(i<L&&!/^```/.test(lines[i])){code+=esc(lines[i])+'\n';i++;}
      o+='<pre class="md-pre"><code class="md-code'+(lang?' lang-'+esc(lang):'')+'">'+(code.replace(/\n$/,''))+'</code></pre>';
      i++;continue;
    }
    // heading
    var hm=line.match(/^(#{1,3})\s+(.*)/);
    if(hm){var hl=hm[1].length;o+='<h'+hl+' class="md-h'+hl+'">'+inline(esc(hm[2]))+'</h'+hl+'>';i++;continue;}
    // blockquote
    if(/^>\s?/.test(line)){
      var bq='';
      while(i<L&&/^>\s?/.test(lines[i])){bq+=inline(esc(lines[i].replace(/^>\s?/,'')))+' ';i++;}
      o+='<blockquote class="md-bq">'+bq.trim()+'</blockquote>';continue;
    }
    // hr
    if(/^(-{3,}|\*{3,}|_{3,})$/.test(line.trim())){o+='<hr class="md-hr">';i++;continue;}
    // unordered list
    if(/^[\*\-\+] /.test(line)){
      o+='<ul class="md-ul">';
      while(i<L&&/^[\*\-\+] /.test(lines[i])){o+='<li>'+inline(esc(lines[i].replace(/^[\*\-\+] /,'')))+'</li>';i++;}
      o+='</ul>';continue;
    }
    // ordered list
    if(/^\d+\.\s/.test(line)){
      o+='<ol class="md-ol">';
      while(i<L&&/^\d+\.\s/.test(lines[i])){o+='<li>'+inline(esc(lines[i].replace(/^\d+\.\s/,'')))+'</li>';i++;}
      o+='</ol>';continue;
    }
    // blank line → paragraph break
    if(line.trim()===''){o+='<div class="md-br"></div>';i++;continue;}
    // paragraph line
    o+='<p class="md-p">'+inline(esc(line))+'</p>';
    i++;
  }
  return o;
}
g.renderMarkdown=md;
})(window);
